funcs.doc:
Spread adapts a variadic callback so it can consume the slice returned by All,
mirroring axios.spread. For example:

	resps, err := axios.All(a, b)
	names := axios.Spread(func(rs ...*axios.Response) []int {
		return []int{rs[0].Status, rs[1].Status}
	})(resps)

examples.code:
package main

import (
	"fmt"
	"io"
	"net/http"
	"net/http/httptest"

	"github.com/malcolmston/axios"
)

func main() {
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		_, _ = io.WriteString(w, `{"name":"Ada Lovelace","age":36}`)
	}))
	defer srv.Close()

	client := axios.New(axios.Config{BaseURL: srv.URL})

	var person struct {
		Name string `json:"name"`
		Age  int    `json:"age"`
	}
	resp, err := client.Get("/user")
	if err != nil {
		fmt.Println("error:", err)
		return
	}
	if err := resp.JSON(&person); err != nil {
		fmt.Println("decode:", err)
		return
	}

	fmt.Println("status:", resp.Status)
	fmt.Println("name:", person.Name)

}

